'use client';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { Progress } from '@/components/ui/progress';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Separator } from '@/components/ui/separator';
import { supply as supplyData } from '@/lib/data';
import { format, addDays } from 'date-fns';
import { es } from 'date-fns/locale';
import { Package, CalendarPlus, Bell, ArrowRight } from 'lucide-react';
import Link from 'next/link';
import { useState, useEffect } from 'react';
import { Supply } from '@/lib/types';
import { Skeleton } from '@/components/ui/skeleton';

export default function SupplyPage() {
  const [supply, setSupply] = useState<Supply | null>(null);

  useEffect(() => {
    setSupply(supplyData);
  }, []);

  if (!supply) {
    return (
      <div className="max-w-4xl mx-auto space-y-8">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Package className="h-6 w-6" />
              Tu Suministro Actual
            </CardTitle>
            <Skeleton className="h-4 w-1/2" />
          </CardHeader>
          <CardContent>
            <Skeleton className="h-4 w-full" />
          </CardContent>
          <CardFooter>
            <Skeleton className="h-10 w-48" />
          </CardFooter>
        </Card>
      </div>
    );
  }

  const progressValue = (supply.pills / supply.pillsPerBottle) * 100;
  const supplyUntilDate = addDays(new Date(), supply.pills);

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Package className="h-6 w-6" />
            Tu Suministro Actual
          </CardTitle>
          <CardDescription>
            Tu suministro actual te cubre hasta el {format(supplyUntilDate, "dd 'de' MMMM, yyyy", { locale: es })}.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-2">
            <div className="flex justify-between text-sm text-muted-foreground">
              <span>{supply.pills} píldoras restantes</span>
              <span>{supply.pillsPerBottle} en total</span>
            </div>
            <Progress value={progressValue} />
          </div>
        </CardContent>
        <CardFooter>
          <Button asChild>
            <Link href="/agenda">
              Gestionar Renovación y Citas
              <ArrowRight className="ml-2 h-4 w-4" />
            </Link>
          </Button>
        </CardFooter>
      </Card>
      
      <div className="grid md:grid-cols-2 gap-8">
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <CalendarPlus className="h-5 w-5" />
              Historial de Suministro
            </CardTitle>
          </CardHeader>
          <CardContent>
            <ul className="space-y-3">
              <li className="flex justify-between">
                <span className="text-muted-foreground">Última entrega:</span>
                <span className="font-medium">{format(supply.lastRefill, "dd/MM/yyyy")}</span>
              </li>
              <li className="flex justify-between">
                <span className="text-muted-foreground">Cantidad:</span>
                <span className="font-medium">{supply.pillsPerBottle} píldoras</span>
              </li>
            </ul>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Bell className="h-5 w-5" />
              Alerta de Renovación
            </CardTitle>
            <CardDescription>
              Recibe un aviso cuando tu suministro se esté agotando.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              <Label htmlFor="reminder-days">Avísame cuando queden:</Label>
              <Select defaultValue="7">
                <SelectTrigger id="reminder-days">
                  <SelectValue placeholder="Selecciona días" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="3">3 días de medicamento</SelectItem>
                  <SelectItem value="7">7 días de medicamento</SelectItem>
                  <SelectItem value="10">10 días de medicamento</SelectItem>
                </SelectContent>
              </Select>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
